2	import { quotePolicy, processClaim, quoteComponent } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office - Quote Operation", () => {
5	  it("should return 0 for empty item list", () => {
6	    expect(quotePolicy([])).toBe(0);
7	  });
8	  it("should return base premium for single Sword", () => {
9	    expect(quotePolicy([{ type: "Sword" }])).toBe(50);
10	  });
11	  it("should return sum of base premiums for multiple items", () => {
12	    expect(quotePolicy([{ type: "Sword" }, { type: "Sword" }])).toBe(100);
13	  });
14	  it("should return base premium for Amulet", () => {
15	    expect(quotePolicy([{ type: "Amulet" }])).toBe(100);
16	  });
17	  it("should return base premium for Staff", () => {
18	    expect(quotePolicy([{ type: "Staff" }])).toBe(75);
19	  });
20	  it("should return base premium for Potion", () => {
21	    expect(quotePolicy([{ type: "Potion" }])).toBe(60);
22	  });
23	  it("should return total with first insurance modifier (+10%)", () => {
24	    expect(quotePolicy([{ type: "Sword", insuranceModifier: "first" }])).toBe(55);
25	  });
26	  it("should return total with loyalty discount (-20%) for 2+ years", () => {
27	    expect(quotePolicy([{ type: "Sword", yearsInsured: 2 }])).toBe(40);
28	  });
29	  it("should return total with cursed item surcharge (50%)", () => {
30	    expect(quotePolicy([{ type: "Sword", cursed: true }])).toBe(75);
31	  });
32	  it("should return total with high enchantment surcharge (30%) for ≥5", () => {
33	    expect(quotePolicy([{ type: "Sword", enchantmentLevel: 5 }])).toBe(65);
34	  });
35	  it("should round premium up (away from zero) in MHPCO's favor", () => {
36	    // Test that rounding goes UP (ceiling) not down (floor): 82.1 should become 83 not 82
37	    // Sword 50: 50 * 1.1 (first) * 1.5 (cursed) = 82.5 -> must round to 83 to favor MHPCO
38	    expect(quotePolicy([{ type: "Sword", insuranceModifier: "first", cursed: true }])).toBe(83);
39	  });
40	  it.todo("should apply processing fee (+5 G) to final premium");
41	  it.todo("should reject unknown item type");
42	});
