1	// MHPCO Claim Office - Policy quoting and claim processing system
2	
3	const ITEM_TYPE_PREMIUMS: Record<string, number> = {
4	  Sword: 50,
5	  Amulet: 100,
6	  Staff: 75,
7	  Potion: 60,
8	};
9	
10	const FIRST_INSURANCE_SURCHARGE = 1.1;
11	const LOYALTY_DISCOUNT = 0.8; // -20% discount for 2+ years
12	const CURSED_ITEM_SURCHARGE = 1.5;
13	const HIGH_ENCHANTMENT_SURCHARGE = 1.3; // +30% for enchantmentLevel >= 5
14	
15	export interface Item {
16	  type: string;
17	  insuranceModifier?: string;
18	  yearsInsured?: number;
19	  cursed?: boolean;
20	  enchantmentLevel?: number;
21	}
22	
23	const applyPremiumMultiplier = (premium: number, shouldApply: boolean, multiplier: number): number => {
24	  return shouldApply ? premium * multiplier : premium;
25	};
26	
27	const applyFirstInsuranceSurcharge = (premium: number, modifier?: string): number => {
28	  return applyPremiumMultiplier(premium, modifier === "first", FIRST_INSURANCE_SURCHARGE);
29	};
30	
31	const applyLoyaltyDiscount = (premium: number, yearsInsured?: number): number => {
32	  return applyPremiumMultiplier(premium, yearsInsured !== undefined && yearsInsured >= 2, LOYALTY_DISCOUNT);
33	};
34	
35	const applyCursedSurcharge = (premium: number, cursed?: boolean): number => {
36	  return applyPremiumMultiplier(premium, cursed === true, CURSED_ITEM_SURCHARGE);
37	};
38	
39	const applyEnchantmentSurcharge = (premium: number, enchantmentLevel?: number): number => {
40	  return applyPremiumMultiplier(premium, enchantmentLevel !== undefined && enchantmentLevel >= 5, HIGH_ENCHANTMENT_SURCHARGE);
41	};
42	
43	export function quotePolicy(items: Item[]): number {
44	  const total = items.reduce((sum, item) => {
45	    const basePremium = ITEM_TYPE_PREMIUMS[item.type] ?? 0;
46	    const modifiedPremium = applyFirstInsuranceSurcharge(basePremium, item.insuranceModifier);
47	    const discountedPremium = applyLoyaltyDiscount(modifiedPremium, item.yearsInsured);
48	    const cursedPremium = applyCursedSurcharge(discountedPremium, item.cursed);
49	    const enchantedPremium = applyEnchantmentSurcharge(cursedPremium, item.enchantmentLevel);
50	    return sum + Math.round(enchantedPremium * 100) / 100;
51	  }, 0);
52	  // Always round up (away from zero) in MHPCO's favor
53	  const rounded = Math.round(total);
54	  return total > rounded ? rounded + 1 : rounded;
55	}
56	
57	export function quoteComponent(items: Item[]): number {
58	  return items.length === 3 ? 60 : 25;
59	}
60	
61	export function processClaim(): number {
62	  throw new Error("Not implemented");
63	}
64	

